import{j as e}from"./ui-vendor-CUvJdy9K.js";import{L as r}from"./LocalLandingPage-BcdhitmQ.js";import{P as a}from"./palette-CKhIElI-.js";import"./react-vendor-CSY-tL5Y.js";import"./index-Dm2gZ_Mj.js";import"./Footer-BjuhafbU.js";import"./phone-CRu6NpsK.js";import"./AnimatedSection-01g3Hqv0.js";import"./Contact-BRVEC_wH.js";import"./use-toast-Nf-M9DeG.js";import"./input-CclBXkxa.js";import"./utils-BLSKlp9E.js";import"./map-pin-BNfU70ob.js";import"./circle-check-big-BkZrLF56.js";import"./sections-DzAg2rcP.js";import"./accordion-BOlHBsSm.js";const t={city:"Västerås",slug:"designbyra-vasteras",serviceKeyword:"Designbyrå",metaTitle:"Designbyrå Västerås – Webbdesign som säljer | LRH Konsult",metaDescription:"Designbyrå i Västerås med fokus på webbdesign, grafisk profil och UX som ger fler kunder. Vi bygger snabba, moderna sajter med React, Figma och Webflow.",heroHeading:"Designbyrå i Västerås – Design som driver affärer",heroDescription:"En vacker hemsida räcker inte – den måste också konvertera. Som designbyrå i Västerås kombinerar vi estetik med strategi: snabb React-kod, genomtänkt UX och en grafisk profil som sticker ut i Västmanland.",icon:a,heroFacts:["100/100 PageSpeed på alla levererade sajter","Webflow, React och Figma – vi väljer rätt verktyg för din budget","Grafisk profil, logotyp och varumärkesidentitet","Lokal designbyrå med kunder i hela Västmanland"],benefits:[{title:"Webbdesign i Västerås",description:"Vi designar hemsidor som ser professionella ut och är byggda för att konvertera besökare till kunder. Varje designval är motiverat av data och användarbeteende – inte bara estetik."},{title:"Grafisk profil & varumärke",description:"Logotyp, färgpalett, typografi och visuell identitet som håller ihop på webben, i sociala medier och i tryck. En stark grafisk profil bygger förtroende redan vid första blicken."},{title:"Webflow & React-utveckling",description:"Som Webflow-konsult och React-utvecklare i Västerås levererar vi sajter med blixtsnabb laddning och sökmotoroptimerad kod. Du väljer det verktyg som passar ditt projekt och budget bäst."},{title:"UX och konverteringsoptimering",description:"Vi analyserar hur dina besökare rör sig på sajten och designar flöden som leder dem mot ett köpbeslut. Bra UX är den billigaste formen av marknadsföring – den löpande SEO-trafikens förstärkare."}],bodyTitle:"Designbyrå i Västerås – Så ser modern webbdesign ut 2026",bodyParagraphs:["Västerås näringsliv är mångsidigt – restauranger, hantverkare, redovisningsbyråer, tech-bolag och tjänsteföretag av alla slag konkurrerar om samma digitala uppmärksamhet. Gemensamt för dem som vinner kampen online är en hemsida som gör tre saker rätt: den laddas snabbt, ser professionell ut och guidar besökaren mot att ta kontakt. Som designbyrå i Västerås är det exakt det vi levererar.","Designprocessen börjar alltid med ett strategimöte. Vi kartlägger vilka kunder du vill nå, vilka sökord de använder och vilka konkurrenter i Västmanland du behöver slå. Utifrån den analysen skapar vi wireframes i Figma som testas och itereras innan en enda rad kod skrivs. Det sparar tid, pengar och säkerställer att slutresultatet faktiskt löser ditt affärsproblem.",'Vi arbetar primärt med React för sajter som kräver hög prestanda och avancerad funktionalitet, och med Webflow för projekt där klienten vill ha enkel innehållshantering utan att kompromissa med design eller hastighet. Som <a href="/tjanster/webbdesign">webbdesignbyrå i Västerås</a> är vi verktygsagnostiska – vi väljer det som passar dig, inte det vi råkar kunna bäst.',"Grafisk profil är en underskattad tillgång för småföretag i Västmanland. När din logotyp, dina färger och din typografi kommunicerar konsekvens och professionalism bygger det förtroende hos nya kunder som aldrig mött dig förut. Vi designar varumärkesidentiteter som fungerar på hemsidan, i Google Business-profilen, i sociala medier och i all kundkommunikation. En välgjord profil är en investering som betalar tillbaka varje gång en potentiell kund ser ditt varumärke.",'Modern webbdesign i Västerås handlar allt mer om prestanda som en del av designen. En vacker sajt som laddas på fyra sekunder är en dålig sajt – Google straffar den och besökare lämnar den. Vi bygger varje sajt med 100/100 PageSpeed som grundkrav, inte som bonus. Det innebär att AVIF- och WebP-bilder, lazy loading, code splitting och optimerade fonter är en del av varje designleverans, inte en eftertanke. <a href="/gratis-seo-analys">Boka en gratis analys</a> för att se hur din nuvarande sajt presterar.'],bodyExtraSections:[{title:"Webflow-konsult i Västerås och Västmanland",paragraphs:["Webflow är ett kraftfullt designverktyg som kombinerar visuell flexibilitet med ren, snabb kod. Som Webflow-konsult i Västerås hjälper vi företag att bygga sajter som ser skräddarsydda ut men är enkla att uppdatera för er internt. Webflow är särskilt lämpat för marknadsföringssajter, portfolio-sidor och smaller e-handelslösningar där designfriheten är viktig.","För mer avancerade krav – komplex interaktivitet, integration med externa API:er eller maximal prestanda – väljer vi React. Båda verktygen ger utmärkt SEO-prestanda förutsatt att de används rätt. Vi designar och bygger sajter som rankar, konverterar och representerar ditt varumärke på bästa sätt i Västerås och hela Västmanland."]},{title:"Designbyrå för hela Västmanland",paragraphs:["Vår designbyrå är baserad i Västerås men vi arbetar med kunder i hela Västmanland – Köping, Sala, Enköping, Fagersta, Hallstahammar och alla kommuner i länet. Alla möten kan ske digitalt, men vi träffar gärna kunder på plats för uppstartsmöten och presentationer.","Vi är en liten, specialiserad designbyrå med fokus på hemsidor och digital närvaro. Det betyder att du alltid pratar direkt med den som designar och bygger din sajt – ingen mellankommunikation, ingen projektledare som vidarebefordrar budskap. Direkt kommunikation ger snabbare beslut och bättre resultat."]}],faq:[{question:"Vad kostar det att anlita en designbyrå i Västerås?",answer:"En ny hemsida kostar typiskt 15 000–60 000 kr beroende på komplexitet. En komplett grafisk profil med logotyp ligger på 8 000–20 000 kr. Vi erbjuder alltid ett fast pris efter specifikation – inga dolda timkostnader. Se mer på vår [prissida](/tjanster/vad-kostar-en-hemsida-2026)."},{question:"Arbetar ni med Webflow eller React?",answer:"Båda. Vi väljer verktyg baserat på ditt projekts krav: Webflow för snabb lansering och enkel innehållshantering, React för hög prestanda och avancerad funktionalitet. Oavsett verktyg levererar vi 100/100 PageSpeed."},{question:"Kan ni hjälpa till med logotyp och grafisk profil?",answer:"Ja. Vi designar logotyp, färgpalett, typografi och ett komplett brand guidelines-dokument. Grafisk profil kan beställas separat eller som del av ett komplett webbprojekt."},{question:"Hur lång tid tar ett webbdesignprojekt?",answer:"En enklare hemsida på 5–8 sidor levereras på 3–4 veckor. Mer komplexa projekt med grafisk profil, animationer och avancerad funktionalitet tar 6–10 veckor. Tidsplanen fastställs i uppstartsmötet."},{question:"Jobbar ni med kunder utanför Västerås?",answer:"Ja, vi arbetar med kunder i hela Västmanland och resten av Sverige. Alla möten kan ske digitalt. Vi har kunder i Köping, Sala, Enköping, Eskilstuna och Stockholm."}]},y=()=>e.jsx(r,{config:t});export{y as default};
